from haystack.components.builders import Pipeline
from vex import Guardrail, Evaluation

approval_guard = Guardrail(name="human-approval")
@approval_guard.policy
def require_approval(recommendation: dict) -> str:
    if recommendation.get('severity') in ['critical', 'high']:
        return Evaluation.BLOCK_WITH_REASON('Requires SOC approval')
    return Evaluation.PASS

pipeline = Pipeline()
pipeline.add_component("approval_check", approval_guard.as_haystack_component())
pipeline.connect("generator", "approval_check")
pipeline.connect("approval_check", "action_executor")
